function.body:
-- Logistice v_ResultStr VARCHAR2(2000):=''; v_Message VARCHAR2(2000):=''; v_Result NUMBER:=1; -- 0=failure v_Record_ID VARCHAR2(32); v_User_ID VARCHAR2(32):='0';
TYPE RECORD IS REF CURSOR; Cur_Parameter RECORD;
v_test1 RECORD; v_test2 RECORD; v_test3 RECORD; cur RECORD; aux NUMBER:=10; loc RECORD; vlistprod RECORD; vprods Record; BEGIN
DBMS_OUTPUT.PUT_LINE('Updating PInstance - Processing ' || P_Instance_ID); v_ResultStr:='PInstanceNotFound'; AD_UPDATE_PINSTANCE(P_Instance_ID, NULL, 'Y', NULL, NULL);
BEGIN --BODY -- Get Parameters v_ResultStr:='ReadingParameters'; FOR Cur_Parameter IN ( SELECT i.Record_ID, i.AD_User_ID, p.ParameterName, p.P_String, p.P_Number, p.P_Date FROM AD_PInstance i LEFT JOIN AD_PInstance_Para p ON i.AD_PInstance_ID = p.AD_PInstance_ID WHERE i.AD_PInstance_ID = P_Instance_ID ORDER BY p.SeqNo ) LOOP v_Record_ID := Cur_Parameter.Record_ID; v_User_ID := Cur_Parameter.AD_User_ID; END LOOP; -- Get Parameter
--- Datos Cabecera --- select AD_Client_ID, AD_Org_ID, ISACTIVE, CREATED, CREATEDBY, UPDATED, UPDATEDBY, em_smvwh_receipdate, EM_Smvwh_Location_To as orig, EM_Smvwh_Location_Transit as dest, EM_Smvai_Route as route into v_test1 from m_movement where m_movement_id = v_Record_ID;
if v_test1.em_smvwh_receipdate is null then
RAISE_APPLICATION_ERROR(-20000, 'Favor, colocar la fecha de recepción de pedidos para crear las líneas') ;
END IF;
--- select * into v_test2 FROM c_order co where co.issotrx ='Y' and co.docstatus='CO' and co.isinvoiced = 'N' and co.isdelivered = 'N' and co.EM_Ssdpm_Dispatcher_Route = v_test1.route and TO_DATE(co.DatePromised, 'DD-MM-YYYY') = v_test1.em_smvwh_receipdate order by created desc; ---
if v_test1.route is null then
RAISE_APPLICATION_ERROR(-20000, 'Ruta no definida ') ;
END IF;
if v_test2 is null then
RAISE_APPLICATION_ERROR(-20000, 'No hay registros aplicables con fecha de recepcion ' || v_test1.em_smvwh_receipdate || ' y ruta ' || v_test1.route) ;
END IF;
if v_test1.orig is null then
RAISE_APPLICATION_ERROR(-20000, 'El movimiento no tiene definido una Ubicacion Origen');
END IF;
if v_test1.dest is null then
RAISE_APPLICATION_ERROR(-20000, 'El movimiento no tiene definido una Ubicacion Transito');
END IF;
if v_test1.route is null then
RAISE_APPLICATION_ERROR(-20000, 'El movimiento no tiene definida una Ruta o esta está mal escrita, por favor verifique');
END IF;
delete from M_MovementLine where M_Movement_id = v_Record_ID;
FOR cur IN ( select col.m_product_id, mprod.c_uom_id, sum(col.qtyordered) as qty FROM c_order co left join c_orderline col on col.c_order_id = co.c_order_id left join m_product mprod on mprod.m_product_id = col.m_product_id where co.issotrx ='Y' and co.docstatus='CO' and co.isinvoiced = 'N' and co.isdelivered = 'N' and co.EM_Ssdpm_Dispatcher_Route = v_test1.route and TO_DATE(co.DatePromised, 'DD-MM-YYYY') = v_test1.em_smvwh_receipdate group by 1, 2
) LOOP
SELECT m_attributesetinstance_id as vattribute into v_test2 FROM M_Storage_Detail where m_product_id = cur.m_product_id and m_locator_id = v_test1.orig and (qtyonhand <> 0 or qtyorderonhand <> 0 or reservedqty <> 0 or allocatedqty <> 0) order by created desc limit 1; -- select * into vlistprod from m_product where m_product_id = cur.m_product_id;
if (vlistprod.IsStocked = 'Y' and vlistprod.ProductType = 'I' and vlistprod.IsBOM = 'Y') then
FOR vprods IN ( select (mppbom.BOMQty * cur.qty) as total, mpp.M_Product_ID from M_Product_BOM mppbom left join m_product mpp on mpp.m_product_id = mppbom.M_ProductBOM_ID where mppbom.M_Product_ID = vlistprod.M_Product_ID and mpp.IsStocked = 'Y' and mpp.ProductType = 'I' and mpp.IsBOM = 'N' )LOOP
SELECT m_attributesetinstance_id as vattribute into v_test3 FROM M_Storage_Detail where m_product_id = vprods.m_product_id and m_locator_id = v_test1.orig and (qtyonhand <> 0 or qtyorderonhand <> 0 or reservedqty <> 0 or allocatedqty <> 0) order by created desc limit 1;
insert into M_MovementLine ( M_MovementLine_id, AD_Client_ID, AD_Org_ID, ISACTIVE, CREATED, CREATEDBY, UPDATED, UPDATEDBY, m_movement_id, m_product_id, aumqty, m_locator_id, m_locatorto_id, c_uom_id, line, MovementQty, M_AttributeSetInstance_ID ) values(get_uuid(), v_test1.AD_Client_ID, v_test1.AD_Org_ID, v_test1.ISACTIVE, v_test1.CREATED, v_test1.CREATEDBY, v_test1.UPDATED, v_test1.UPDATEDBY, v_Record_ID, vprods.m_product_id, vprods.total, v_test1.orig, v_test1.dest, cur.c_uom_id, aux, vprods.total, v_test3.vattribute
) ; aux:=aux+10;
END LOOP;
-- RAISE_APPLICATION_ERROR(-20000, 'Producto tipo lista ' || vprods.total);
End IF;
-- if (vlistprod.IsStocked = 'Y' and vlistprod.ProductType = 'I' and vlistprod.IsBOM = 'N') then insert into M_MovementLine ( M_MovementLine_id, AD_Client_ID, AD_Org_ID, ISACTIVE, CREATED, CREATEDBY, UPDATED, UPDATEDBY, m_movement_id, m_product_id, aumqty, m_locator_id, m_locatorto_id, c_uom_id, line, MovementQty, M_AttributeSetInstance_ID ) values(get_uuid(), v_test1.AD_Client_ID, v_test1.AD_Org_ID, v_test1.ISACTIVE, v_test1.CREATED, v_test1.CREATEDBY, v_test1.UPDATED, v_test1.UPDATEDBY, v_Record_ID, cur.m_product_id, cur.qty, v_test1.orig, v_test1.dest, cur.c_uom_id, aux, cur.qty, v_test2.vattribute
) ; aux:=aux+10; END IF;
END LOOP;
-- RAISE_APPLICATION_ERROR(-20000, 'Total de registros a sumar ' || aux);
-- RAISE_APPLICATION_ERROR(-20000, 'Transaccion exitosa') ;
DBMS_OUTPUT.PUT_LINE('Updating PInstance - Finished ' || v_Message); AD_UPDATE_PINSTANCE(P_Instance_ID, NULL, 'N', v_Result, v_Message);
RETURN; END; --BODY
EXCEPTION WHEN OTHERS THEN v_ResultStr:= '@ERROR=' || SQLERRM; DBMS_OUTPUT.PUT_LINE( v_ResultStr) ; ROLLBACK; AD_UPDATE_PINSTANCE(P_Instance_ID, NULL, 'N', 0, v_ResultStr); END SMVWH_CREATELINES
